// R-style formula grammar for pest parser
// Supports basic formula syntax: y ~ x1 + x2*x3

WHITESPACE = _{ " " | "\t" | "\n" | "\r" }

// Top-level formula structure
formula = { SOI ~ response ~ "~" ~ terms ~ EOI }

// Response variable (left side of ~)
response = { variable }

// Right side terms (predictors)
terms = { term ~ ("+" ~ term)* }

// Individual term (variable or interaction)
term = { interaction | variable | "1" }

// Interaction term (x1*x2 or x1:x2)
interaction = { variable ~ ("*" | ":") ~ variable ~ ("*" ~ variable | ":" ~ variable)* }

// Variable name (R identifier rules)
variable = { ASCII_ALPHA ~ (ASCII_ALPHANUMERIC | "_" | ".")* }

// Number (for intercept specification)
number = { ASCII_DIGIT+ }

