   101→/// Incomplete beta function approximation
   102→/// This is a simplified implementation - a full implementation would use continued fractions
   103→fn incomplete_beta(a: f64, b: f64, x: f64) -> f64 {
   104→    if x <= 0.0 {
   105→        return 0.0;
   106→    }
   107→    if x >= 1.0 {
   108→        return 1.0;
   109→    }
   110→
   111→    // For small parameters, use a simple series approximation
   112→    // This is not highly accurate but sufficient for basic statistical inference
   113→    let mut result = 0.0;
   114→    let mut term = x.powf(a) * (1.0 - x).powf(b) / (a * beta_function(a, b));
